package main

import (
	"fmt"
	"slices"
	"strconv"
	"strings"
)

func main() {
	var n int
	fmt.Scan(&n)
	v := make([]int, n)
	for i := range v {
		fmt.Scan(&v[i])
	}
	slices.Sort(v)
	parts := make([]string, n)
	for i, x := range v {
		parts[i] = strconv.Itoa(x)
	}
	fmt.Println(strings.Join(parts, " "))
}
